arguments.command:
cd /app && python3 -c "
seqs={}
name=None
for line in open('sequences.fasta'):
    line=line.strip()
    if line.startswith('>'):
        name=line[1:]; seqs[name]=''
    else:
        seqs[name]+=line.lower()
inp=seqs['input']
P=213
comp={'a':'t','t':'a','g':'c','c':'g'}
def rc(s): return ''.join(comp[c] for c in reversed(s))
import subprocess
def tm(s):
    o=subprocess.run(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',s.upper()],capture_output=True,text=True)
    return float(o.stdout.strip())
print('FORWARD anneal (downstream top strand):')
for b in range(15,31):
    d=inp[P:P+b]
    print(b, d.upper(), round(tm(d),2))
print('REVERSE anneal (revcomp upstream):')
for a in range(15,31):
    u=inp[P-a:P]
    r=rc(u)
    print(a, r.upper(), round(tm(r),2))
"

